+	if err != nil {
+		t.Fatalf("NewSession: %v", err)
+	}
+	defer sess.Close()
+
+	var events []SessionEvent
+	var mu sync.Mutex
+	done := make(chan struct{})
+	go func() {
+		for ev := range sess.Events() {
+			mu.Lock()
+			events = append(events, ev)
+			mu.Unlock()
+		}
+		close(done)
+	}()
+
